/* ── Helpers ── */
const isAct = (r) => r?.["sbaa__Active__c"] === true || r?.["sbaa__Active__c"] === "true";
const isUserActive = (u) => u?.["IsActive"] === true || u?.["IsActive"] === "true";
const normId = (id) => (id ? String(id).substring(0, 15) : "");
const isSfId = (s) => /^[a-zA-Z0-9]{15}$/.test(s) || /^[a-zA-Z0-9]{18}$/.test(s);
const sfIdEq = (a, b) => {
  if (isSfId(a) && isSfId(b)) return a.substring(0, 15) === b.substring(0, 15);
  return a.toLowerCase() === b.toLowerCase();
};

const EMBEDDED_DATA = "";

async function loadEmbeddedData() {
  const binary = atob(EMBEDDED_DATA);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  const ds = new DecompressionStream("gzip");
  const writer = ds.writable.getWriter();
  writer.write(bytes);
  writer.close();
  const reader = ds.readable.getReader();
  const chunks = [];
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    chunks.push(value);
  }
  const totalLength = chunks.reduce((sum, c) => sum + c.length, 0);
  const result = new Uint8Array(totalLength);
  let offset = 0;
  for (const chunk of chunks) { result.set(chunk, offset); offset += chunk.length; }
  return JSON.parse(new TextDecoder().decode(result));
}

function parseCSV(t) {
  return Papa.parse(t, { header: true, dynamicTyping: true, skipEmptyLines: true, delimitersToGuess: [",", "\t", "|", ";"] }).data;
}

function copyText(text, setCopied, key) {
  try {
    const ta = document.createElement("textarea");
    ta.value = text;
    ta.style.position = "fixed";
    ta.style.left = "-9999px";
    document.body.appendChild(ta);
    ta.select();
    document.execCommand("copy");
    document.body.removeChild(ta);
    setCopied(key);
    setTimeout(() => setCopied(null), 2000);
  } catch {}
}

/* ── Variable Tracing ── */
function traceVariable(variable, qlData) {
  if (!qlData?.length || !variable) return null;
  const aggField = String(variable["sbaa__AggregateField__c"] || "").trim();
  const aggFn = String(variable["sbaa__AggregateFunction__c"] || "").toUpperCase();
  const filtField = String(variable["sbaa__FilterField__c"] || "").trim();
  const filtVal = String(variable["sbaa__FilterValue__c"] != null ? variable["sbaa__FilterValue__c"] : "").trim();

  let lines = qlData;
  if (filtField && filtVal) {
    lines = lines.filter((l) => String(l[filtField] || "").trim().toLowerCase() === filtVal.toLowerCase());
  }
  if (!lines.length) return { varName: variable.Name, aggFn, aggField, filtField, filtVal, result: 0, contributing: [], totalLines: 0, allFiltered: true };

  const vals = lines.map((l) => ({
    line: l,
    name: l["SBQQ__ProductName__c"] || l["Name"] || "Unknown",
    num: l["SBQQ__Number__c"],
    val: parseFloat(l[aggField]) || 0,
  }));

  let result = 0, contributing = [];
  switch (aggFn) {
    case "MAX": result = _.maxBy(vals, "val")?.val || 0; contributing = vals.filter((v) => v.val === result); break;
    case "MIN": result = _.minBy(vals, "val")?.val || 0; contributing = vals.filter((v) => v.val === result); break;
    case "SUM": result = _.sumBy(vals, "val"); contributing = vals.filter((v) => v.val !== 0); break;
    case "COUNT": result = vals.length; contributing = vals; break;
    default: result = _.maxBy(vals, "val")?.val || 0; contributing = vals.filter((v) => v.val === result);
  }
  return { varName: variable.Name, aggFn, aggField, filtField, filtVal, result, contributing, totalLines: lines.length, allFiltered: false };
}

/* ── Condition Evaluation ── */
function evalCond(c, rec, vMap, qlData) {
  const field = (c["sbaa__TestedField__c"] || "").trim();
  const op = (c["sbaa__Operator__c"] || "").toLowerCase().trim();
  const fv = c["sbaa__FilterValue__c"];
  let fs = fv != null ? String(fv).trim() : "";
  const tvn = (c["sbaa__TestedVariable__r.Name"] || "").trim();
  const fvn = (c["sbaa__FilterVariable__r.Name"] || "").trim();

  // Variable-based condition
  if (!field && tvn && vMap && qlData?.length) {
    const v = vMap[tvn];
    if (v) {
      const tr = traceVariable(v, qlData);
      if (tr) {
        let expVal = fs, fTrace = null;
        if (fvn) { const fv2 = vMap[fvn]; if (fv2) { const ft = traceVariable(fv2, qlData); if (ft) { expVal = String(ft.result); fTrace = ft; } } }
        const as2 = String(tr.result), an2 = parseFloat(as2), efn = parseFloat(expVal), bn2 = !isNaN(an2) && !isNaN(efn);
        let pass2 = false, ol2 = op;
        switch (op) {
          case "equals": pass2 = bn2 ? an2 === efn : as2 === expVal; ol2 = "="; break;
          case "not equals": pass2 = bn2 ? an2 !== efn : as2 !== expVal; ol2 = "≠"; break;
          case "greater than": pass2 = bn2 ? an2 > efn : false; ol2 = ">"; break;
          case "less than": pass2 = bn2 ? an2 < efn : false; ol2 = "<"; break;
          case "greater or equal": case "greater or equals": pass2 = bn2 ? an2 >= efn : false; ol2 = "≥"; break;
          case "less or equal": case "less or equals": pass2 = bn2 ? an2 <= efn : false; ol2 = "≤"; break;
          default: pass2 = bn2 ? an2 === efn : as2 === expVal;
        }
        const fLabel = fvn ? `${fvn} → ${expVal}` : expVal;
        return { field: `${tvn} (${v["sbaa__AggregateFunction__c"] || ""} of ${v["sbaa__AggregateField__c"] || ""})`, op: ol2, filterVal: fLabel, actualVal: String(Math.round(an2 * 10000) / 10000), pass: pass2, rawOp: op, isVariable: true, trace: tr, filterTrace: fTrace, testedVarName: tvn, filterVarName: fvn };
      }
    }
  }
  if (!field) return { field: tvn || "(approval variable)", op, filterVal: fs, actualVal: "(upload quote lines to evaluate)", pass: false, rawOp: op, isVariable: true };

  let filterTrace2 = null, hasFilterVar = false;
  if (fvn && vMap && qlData?.length) {
    const fv3 = vMap[fvn];
    if (fv3) { const ft2 = traceVariable(fv3, qlData); if (ft2) { fs = String(ft2.result); filterTrace2 = ft2; hasFilterVar = true; } }
  }

  let av = rec[field];
  if (av === undefined || av === null) av = "";
  const as = String(av).trim(), an = parseFloat(as), fn2 = parseFloat(fs), bn = !isNaN(an) && !isNaN(fn2), isBlank = as === "" || av === undefined || av === null;

  if (isBlank && ["greater than", "less than", "greater or equal", "greater or equals", "less or equal", "less or equals", "starts with", "contains"].indexOf(op) >= 0) {
    const bOl = op === "greater than" ? ">" : op === "less than" ? "<" : op.startsWith("greater or equal") ? "≥" : op.startsWith("less or equal") ? "≤" : op;
    return { field, op: bOl, filterVal: hasFilterVar ? `${fvn} → ${fs}` : fs, actualVal: "(blank)", pass: false, rawOp: op, filterTrace: filterTrace2, filterVarName: hasFilterVar ? fvn : null };
  }

  const csv = fs.indexOf(",") >= 0 ? fs.split(",").map((v) => v.trim()) : null;
  let pass = false, ol = op;
  switch (op) {
    case "equals": pass = csv ? csv.some((v) => sfIdEq(as, v)) : sfIdEq(as, fs); ol = "="; break;
    case "not equals": pass = csv ? !csv.some((v) => sfIdEq(as, v)) : !sfIdEq(as, fs); ol = "≠"; break;
    case "greater than": pass = bn ? an > fn2 : false; ol = ">"; break;
    case "less than": pass = bn ? an < fn2 : false; ol = "<"; break;
    case "greater or equal": case "greater or equals": pass = bn ? an >= fn2 : false; ol = "≥"; break;
    case "less or equal": case "less or equals": pass = bn ? an <= fn2 : false; ol = "≤"; break;
    case "starts with": pass = as.toLowerCase().startsWith(fs.toLowerCase()); break;
    case "contains": pass = as.toLowerCase().indexOf(fs.toLowerCase()) >= 0; break;
    case "does not contain": pass = isBlank ? true : as.toLowerCase().indexOf(fs.toLowerCase()) < 0; break;
    default: pass = csv ? csv.some((v) => sfIdEq(as, v)) : sfIdEq(as, fs);
  }
  return { field, op: ol, filterVal: hasFilterVar ? `${fvn} → ${fs}` : fs, actualVal: as, pass, rawOp: op, filterTrace: filterTrace2, filterVarName: hasFilterVar ? fvn : null };
}

/* ── Rule Evaluation ── */
function evalRule(rule, conds, rec, vMap, qlData) {
  if (!conds.length) return { triggered: true, results: [], reason: "No conditions — matches all records", formulaBreakdown: null, usedIndices: null };
  const results = conds.map((c, i) => {
    const r = evalCond(c, rec, vMap, qlData);
    r.index = Math.round(c["sbaa__Index__c"] || (i + 1));
    // Attach variable definitions so the UI can explain what the variable computes,
    // even when no Quote Lines CSV is uploaded (no live trace available).
    const tvn = (c["sbaa__TestedVariable__r.Name"] || "").trim();
    const fvn = (c["sbaa__FilterVariable__r.Name"] || "").trim();
    const tv = tvn && vMap ? vMap[tvn] : null;
    const fv = fvn && vMap ? vMap[fvn] : null;
    const pickDef = (v) => v ? {
      name: v.Name,
      target: v["sbaa__TargetObject__c"],
      aggFn: v["sbaa__AggregateFunction__c"],
      aggField: v["sbaa__AggregateField__c"],
      filtField: v["sbaa__FilterField__c"],
      filtVal: v["sbaa__FilterValue__c"],
      filtOp: v["sbaa__Operator__c"],
    } : null;
    r.testedVariable = pickDef(tv);
    r.filterVariable = pickDef(fv);
    return r;
  });
  const cm = (rule["sbaa__ConditionsMet__c"] || "All").toLowerCase();
  const ac = rule["sbaa__AdvancedCondition__c"];
  let triggered = false;

  if (cm === "all") triggered = results.every((r) => r.pass);
  else if (cm === "any") triggered = results.some((r) => r.pass);
  else if (cm === "custom" && ac) {
    try {
      let e = ac;
      const idxMap = {};
      conds.forEach((c, i) => { idxMap[Math.round(c["sbaa__Index__c"] || (i + 1))] = results[i]; });
      Object.keys(idxMap).map(Number).sort((a, b) => b - a).forEach((idx) => { e = e.replace(new RegExp("\\b" + idx + "\\b", "g"), idxMap[idx].pass ? "true" : "false"); });
      e = e.replace(/\bAND\b/gi, "&&").replace(/\bOR\b/gi, "||");
      triggered = new Function("return(" + e + ")")();
    } catch { triggered = results.every((r) => r.pass); }
  } else triggered = results.every((r) => r.pass);

  let fb = null;
  if (cm === "custom" && ac) {
    const im2 = {};
    conds.forEach((c, i) => { im2[Math.round(c["sbaa__Index__c"] || (i + 1))] = results[i]; });
    fb = ac.split(/\bOR\b/i).map((g) => {
      g = g.trim();
      const nums = [];
      let re = /\b(\d+)\b/g, m;
      while ((m = re.exec(g)) !== null) nums.push(parseInt(m[1]));
      let expr = g;
      nums.slice().sort((a, b) => b - a).forEach((idx) => { const r = im2[idx]; expr = expr.replace(new RegExp("\\b" + idx + "\\b", "g"), r ? (r.pass ? "true" : "false") : "false"); });
      expr = expr.replace(/\bAND\b/gi, "&&").replace(/[()]/g, "").trim();
      let gr = false;
      try { gr = new Function("return(" + expr + ")")(); } catch {}
      return {
        group: g, result: gr,
        parts: nums.sort((a, b) => a - b).map((idx) => { const r = im2[idx]; return { idx, pass: r ? r.pass : false, field: r ? r.field : "?" }; }),
      };
    });
  }
  // For Custom rules, capture which condition indices the formula actually references,
  // so the UI can hide conditions that exist on the rule but aren't part of the formula.
  let usedIndices = null;
  if (cm === "custom" && ac) {
    const us = [];
    let re = /\b(\d+)\b/g, m;
    while ((m = re.exec(ac)) !== null) us.push(parseInt(m[1]));
    usedIndices = Array.from(new Set(us));
  }

  return { triggered, results, reason: null, formulaBreakdown: fb, usedIndices };
}

